import java.io.*;
import org.apache.commons.lang.StringEscapeUtils; // Import Apache Commons Lang library for escaping HTML characters

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {

        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String name = reader.readLine();

        // Sanitize user input to prevent XSS attacks
        String sanitizedName = StringEscapeUtils.escapeHtml(name);

        System.out.println("Hello, " + sanitizedName + "! Welcome to our website.");
    }
}

### Explanation:
